def test_submit_leave_request_exactly_30_business_days(auth_client, clean_leave_state, next_business_day, business_days_end):
    start = next_business_day(offset=1)
    end = business_days_end(start, count=30)
    payload = {"start_date": start, "end_date": end, "leave_type": "annual"}

    resp = auth_client.post("/leave-requests/new", json=payload)

    assert resp.status_code == 201
    body = resp.json()
    assert body["status"] == "pending"
    assert body.get("hr_approval_required", False) is False

def test_submit_leave_request_start_after_end_returns_400(auth_client, next_business_day, assert_no_leave_created):
    start = next_business_day(offset=5)
    end = next_business_day(offset=1)
    payload = {"start_date": start, "end_date": end, "leave_type": "annual"}

    resp = auth_client.post("/leave-requests/new", json=payload)

    assert resp.status_code == 400
    body = resp.json()
    assert body.get("error_code") == "INVALID_DATE_RANGE"
    assert_no_leave_created(auth_client.user_id, start, end)

def test_submit_leave_request_exceeds_30_days_without_hr_admin_returns_422(auth_client, clean_leave_state, next_business_day, business_days_end, assert_no_leave_created):
    start = next_business_day(offset=1)
    end = business_days_end(start, count=31)
    payload = {"start_date": start, "end_date": end, "leave_type": "annual"}

    resp = auth_client.post("/leave-requests/new", json=payload)

    assert resp.status_code == 422
    body = resp.json()
    assert body.get("error_code") == "HR_ADMIN_APPROVAL_REQUIRED"
    assert_no_leave_created(auth_client.user_id, start, end)
